arguments.argument:
if bSizeUp=false
{
  sizeMod-=0.002
  if sizeMod<=0 {bSizeUp=true}
}
else
{
  sizeMod+=0.002
  if sizeMod>=0.07 {bSizeUp=false}
}

if surface_exists(surf)
{
  surface_set_target(surf)
  draw_clear_alpha(c_black,1)
  draw_set_blend_mode(bm_subtract)
  draw_sprite_ext(sSurfOmniLightA,0,oPlayer1.x,oPlayer1.y-26,2+sizeMod,2+sizeMod,0,c_white,1)
  if oIdentifier.bChaoActive=1 {draw_sprite_ext(sSurfOmniLightA,0,oIdentifier.x,oIdentifier.y,2+sizeMod,2+sizeMod,0,c_white,1)}
  with oEnemyBase
  {
    draw_sprite_ext(sSurfOmniLightA,0,x,y,1.1+oSurfLightAll.sizeMod,1.1+oSurfLightAll.sizeMod,0,c_white,0.65)
  }
  with oLittleBirdStaticA
  {
    draw_sprite_ext(sSurfOmniLightA,0,x,y,0.33+oSurfLightAll.sizeMod,0.33+oSurfLightAll.sizeMod,0,c_white,0.6)
  }
  with oLC_Spotlights
  {
    draw_sprite_ext(sSurfSpotLightA,0,x,y,image_xscale+oSurfLightAll.sizeMod,image_yscale+oSurfLightAll.sizeMod,image_angle,c_white,0.8)
  }
  with oCaveTorch
  {
    draw_sprite_ext(sSurfOmniLightA,0,x,y-8,1.25+oSurfLightAll.sizeMod,1.25+oSurfLightAll.sizeMod,0,c_white,0.75)
  }
  with oCastlePlatMaker
  {
    draw_sprite_ext(sSurfOmniLightA,0,x,y,1.25+oSurfLightAll.sizeMod,1.25+oSurfLightAll.sizeMod,0,c_white,0.8)
  }
  with oMCastle_PlatA
  {
    draw_sprite_ext(sSurfOmniLightA,0,x,y,1.5+oSurfLightAll.sizeMod,1.5+oSurfLightAll.sizeMod,0,c_white,0.8)
  }
  with oMCastle_PlatB
  {
    draw_sprite_ext(sSurfOmniLightA,0,x,y,1.25+oSurfLightAll.sizeMod,1.25+oSurfLightAll.sizeMod,0,c_white,0.75)
  }
  with oMCastle_TorchA
  {
    draw_sprite_ext(sSurfOmniLightA,0,x,y-4,1.33+oSurfLightAll.sizeMod,1.33+oSurfLightAll.sizeMod,0,c_white,0.9)
  }
  if instance_exists(oWepEf_Light)
  {
    with oWepEf_Light
    {
      draw_sprite_ext(sSurfOmniLightA,0,x,y,image_xscale,image_yscale,image_angle,c_white,image_alpha)
    }
  }
  if room=rDistFinal_Pong
  {
    with oFB_PlayerPaddle
    {
      draw_sprite_ext(sSurfOmniLightA,0,x,y,0.9+oSurfLightAll.sizeMod,0.9+oSurfLightAll.sizeMod,0,c_white,1)
    }
    with oFB_HexorPaddle
    {
      draw_sprite_ext(sSurfOmniLightA,0,x,y,0.9+oSurfLightAll.sizeMod,0.9+oSurfLightAll.sizeMod,0,c_white,1)
    }
    with oFB_PongBullet
    {
      draw_sprite_ext(sSurfOmniLightA,0,x,y,0.4+oSurfLightAll.sizeMod,0.4+oSurfLightAll.sizeMod,0,c_white,0.9)
    }
    with oFB_PlayerBullet
    {
      draw_sprite_ext(sSurfOmniLightA,0,x,y,0.4+oSurfLightAll.sizeMod,0.4+oSurfLightAll.sizeMod,0,c_white,0.9)
    }
  }
  surface_reset_target()
  draw_set_blend_mode(bm_normal)
}
